$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$recommend_html = [System.Text.Encoding]::UTF8.GetString($bytes)

$reviews = @("jilianyun.html", "edgenova.html", "guangnianti.html", "huanyuyun.html", "kexinyun.html", "kuaili.html", "shunyun.html", "sujie.html")
foreach ($rev in $reviews) {
    $path = ".\articles\$rev"
    if (Test-Path $path) {
        $content = [System.IO.File]::ReadAllText($path, [System.Text.Encoding]::UTF8)
        $content = [System.Text.RegularExpressions.Regex]::Replace($content, '(?s)<!-- Recommended Links -->.*?</div>\s*</div>', $recommend_html)
        $content = [System.Text.RegularExpressions.Regex]::Replace($content, '(?s)<div class="related-recommendations".*?</ul>\s*</div>', $recommend_html)
        [System.IO.File]::WriteAllText($path, $content, [System.Text.Encoding]::UTF8)
        Write-Host "Fixed $rev"
    }
}

$seo_b64 = ""
$seo_bytes = [System.Convert]::FromBase64String($seo_b64)
$seo_footer = [System.Text.Encoding]::UTF8.GetString($seo_bytes)

$index_path = ".\index.html"
$index_content = [System.IO.File]::ReadAllText($index_path, [System.Text.Encoding]::UTF8)
$index_content = [System.Text.RegularExpressions.Regex]::Replace($index_content, '(?s)<!-- SEO Links Section -->.*?</section>', $seo_footer)
[System.IO.File]::WriteAllText($index_path, $index_content, [System.Text.Encoding]::UTF8)
Write-Host "Fixed index.html"
